1	export type Cell = [number, number]; // [x, y]
2	
3	const toKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: Cell[] = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [0, -1],           [0, 1],
8	  [1, -1],  [1, 0],  [1, 1],
9	];
10	
11	function neighborsOf([x, y]: Cell): Cell[] {
12	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	}
14	
15	function countLiveNeighbors(cell: Cell, living: Set<string>): number {
16	  return neighborsOf(cell).filter((n) => living.has(toKey(n))).length;
17	}
18	
19	function isAliveNextGeneration(isAlive: boolean, liveNeighbors: number): boolean {
20	  return liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
21	}
22	
23	function candidateCells(cells: Cell[]): Cell[] {
24	  const candidates = new Map<string, Cell>();
25	  for (const cell of cells) {
26	    candidates.set(toKey(cell), cell);
27	    for (const neighbor of neighborsOf(cell)) candidates.set(toKey(neighbor), neighbor);
28	  }
29	  return [...candidates.values()];
30	}
31	
32	export function nextGeneration(cells: Cell[]): Cell[] {
33	  const living = new Set(cells.map(toKey));
34	
35	  const willBeAlive = (cell: Cell): boolean =>
36	    isAliveNextGeneration(living.has(toKey(cell)), countLiveNeighbors(cell, living));
37	
38	  return candidateCells(cells).filter(willBeAlive);
39	}
