1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  // Simplest case: empty grid
6	  it("should return empty for an empty grid — [] → []", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	
10	  // Single cell dies (underpopulation, 0 neighbors)
11	  it("should kill a single cell with no neighbors — [(0,0)] → []", () => {
12	    expect(nextGeneration([[0, 0]])).toEqual([]);
13	  });
14	
15	  // Rule 1 – Underpopulation: pair each with 1 neighbor dies
16	  it("should kill both cells of a pair with 1 neighbor each — [(0,1),(1,1)] → []", () => {
17	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
18	  });
19	
20	  // Rule 2 – Survival: live cell with 2 or 3 neighbors lives on
21	  it("should keep a live cell alive with 2 neighbors — center (1,0) survives", () => {
22	    // Horizontal row of 3; center (1,0) has 2 live neighbors → survives.
23	    expect(nextGeneration([[0, 0], [1, 0], [2, 0]])).toContainEqual([1, 0]);
24	  });
25	
26	  // Rule 4 – Reproduction: dead cell with exactly 3 neighbors becomes alive
27	  it("should bring a dead cell to life with exactly 3 neighbors — (1,1) becomes alive", () => {
28	    // Dead cell (1,1) has live neighbors (0,0),(1,0),(0,1) → exactly 3 → born.
29	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toContainEqual([1, 1]);
30	  });
31	
32	  // Rule 3 – Overpopulation: live cell with > 3 neighbors dies
33	  it("should kill a live cell with 4 neighbors — center (1,1) dies", () => {
34	    // Center (1,1) is live with 4 orthogonal live neighbors → overpopulation.
35	    expect(
36	      nextGeneration([[1, 1], [1, 0], [0, 1], [2, 1], [1, 2]]),
37	    ).not.toContainEqual([1, 1]);
38	  });
39	
40	  // Pattern: Block still life
41	  it("should keep a block unchanged — [(0,0),(1,0),(0,1),(1,1)] stable", () => {
42	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
43	    const result = nextGeneration(block);
44	    expect(result).toHaveLength(4);
45	    for (const cell of block) expect(result).toContainEqual(cell);
46	  });
47	
48	  // Pattern: Blinker oscillator (exercises negative coordinates)
49	  it("should oscillate a blinker — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
50	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
51	    expect(result).toHaveLength(3);
52	    for (const cell of [[-1, 1], [0, 1], [1, 1]] as Cell[]) {
53	      expect(result).toContainEqual(cell);
54	    }
55	  });
56	});
